            ("Create an alert processing rule across the RG", "az monitor alert-processing-rule create --name \"apr-add-ag\" --resource-group \"$RG\" --scopes \"/subscriptions/$SUB_ID/resourceGroups/$RG\" --rule-type AddActionGroups --action-groups \"$AG_ID\""),
