            ("Deploy two VMs with an NSG allowing SSH/HTTP", "az vm create -g \"$RG\" -n \"vm-web\" --image Ubuntu2204 --size Standard_B1s --vnet-name \"vnet-az104-lab24\" --subnet \"subnet-app\" --admin-username azureuser --generate-ssh-keys --public-ip-sku Standard --nsg \"nsg-web\""),
